export const metadata: Metadata = {
  title: 'Admin Dashboard',
  description: 'Admin area with auth protection',
}

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode
}>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  )
}

